sql:
SELECT course_name, location, total_holes
FROM golf_courses
WHERE total_holes >= 18;

SELECT course_name, location, total_holes
FROM golf_courses
ORDER BY course_name;

SELECT hole_number, white_yards
FROM holes
WHERE water_hazards = 1;

SELECT DISTINCT tp.score
FROM tournament_participants tp
WHERE tp.player_id = 1;

SELECT course_name, total_holes
FROM golf_courses
ORDER BY total_holes DESC;

SELECT AVG(fairways_hit) AS average_fairways_hit
FROM rounds
WHERE course_id = 1;

SELECT COUNT(course_id) AS total_courses, location, grass_type
FROM golf_courses
GROUP BY location, grass_type;

SELECT COUNT(*) 
FROM golf_courses 
WHERE location LIKE '%Colorado%';

SELECT tee_box_name
FROM tee_boxes
WHERE tee_box_id = 0;

SELECT COUNT(DISTINCT rounds.round_id) AS total_rounds
FROM rounds
WHERE rounds.course_id IN (
    SELECT course_id
    FROM maintenance_records
);
